"use client";

import PageHero from "@/components/PageHero";
import { useTranslations } from "next-intl";
import { CheckCircle2, Phone, ArrowRight } from "lucide-react";
import { motion } from "framer-motion";
import { Link } from "@/i18n/routing";

interface Props {
    pageKey: string;
    bgGradient?: string;
    imageSrc?: string;
}

export default function GenericMSPView({
    pageKey,
    bgGradient = "from-blue-900/40 via-slate-900 to-slate-900",
    imageSrc = "/images/unsplash/photo-1551434678-e076c223a692.jpg"
}: Props) {
    const t = useTranslations(`MSP_Pages.${pageKey}`);
    const tNav = useTranslations("Navigation");

    // We know most pages have up to 4 features
    const featureIndices = [0, 1, 2, 3];
    const hasFeatures = t.has("features.0");
    const isSupportCenter = pageKey === "support_center";

    return (
        <div className="min-h-screen bg-[#f8fafc]">
            <PageHero
                title={t("title")}
                subtitle={t("subtitle")}
                bgGradient={bgGradient}
            />

            <div className="container mx-auto px-4 py-24">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">

                    {/* Content Section */}
                    <div className="space-y-8">
                        <motion.div
                            initial={{ opacity: 0, x: -20 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            transition={{ duration: 0.6 }}
                            viewport={{ once: true }}
                        >
                            <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-6 leading-tight">
                                {t("title")}
                            </h2>
                            <p className="text-lg text-slate-600 leading-relaxed mb-8">
                                {t("desc")}
                            </p>

                            {isSupportCenter && t.has("phone") && (
                                <div className="mt-8 p-8 bg-blue-50 border border-blue-100 rounded-3xl flex items-center gap-6">
                                    <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg">
                                        <Phone className="w-8 h-8" />
                                    </div>
                                    <div>
                                        <p className="text-sm font-semibold text-blue-600 uppercase tracking-wider mb-1">
                                            {t("phone_label")}
                                        </p>
                                        <p className="text-3xl font-bold text-slate-900">
                                            {t("phone")}
                                        </p>
                                    </div>
                                </div>
                            )}

                            {hasFeatures && (
                                <div className="space-y-4 mt-8">
                                    {featureIndices.map((i) => {
                                        if (!t.has(`features.${i}`)) return null;
                                        return (
                                            <div key={i} className="flex gap-4 items-start">
                                                <div className="mt-1">
                                                    <CheckCircle2 className="w-6 h-6 text-blue-600" />
                                                </div>
                                                <p className="text-lg text-slate-700">
                                                    {t(`features.${i}`)}
                                                </p>
                                            </div>
                                        );
                                    })}
                                </div>
                            )}

                            <div className="mt-12 flex items-center gap-4">
                                <Link
                                    href="/contact"
                                    className="px-8 py-4 bg-blue-600 text-white rounded-xl font-semibold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/20 inline-flex items-center gap-2"
                                >
                                    {tNav("contact")} <ArrowRight className="w-5 h-5" />
                                </Link>
                            </div>
                        </motion.div>
                    </div>

                    {/* Image Section */}
                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6 }}
                        viewport={{ once: true }}
                        className="relative"
                    >
                        <div className="aspect-[4/3] rounded-[2rem] overflow-hidden shadow-2xl border border-white/20">
                            <img
                                src={imageSrc}
                                alt={t("title")}
                                className="w-full h-full object-cover hover:scale-105 transition-transform duration-700"
                            />
                            <div className="absolute inset-0 bg-gradient-to-tr from-blue-900/40 to-transparent mix-blend-multiply" />
                        </div>

                        {/* Decorative floating elements */}
                        <div className="absolute -top-6 -right-6 w-24 h-24 bg-blue-500/10 rounded-full blur-2xl" />
                        <div className="absolute -bottom-8 -left-8 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl" />
                    </motion.div>

                </div>
            </div>
        </div>
    );
}

"use client";

import PageHero from "@/components/PageHero";
import { useTranslations } from "next-intl";
import { CheckCircle2, ArrowRight, Building2, Globe } from "lucide-react";
import { motion } from "framer-motion";
import { Link } from "@/i18n/routing";

interface Props {
    bgGradient?: string;
    imageSrc?: string;
}

export default function OurClientsView({
    bgGradient = "from-blue-900/40 via-slate-900 to-slate-900",
    imageSrc = "/images/unsplash/photo-1556761175-4b46a572b786.jpg"
}: Props) {
    const t = useTranslations("MSP_Pages.our_clients");
    const tNav = useTranslations("Navigation");

    // Features handling
    const featureIndices = [0, 1, 2, 3];
    const hasFeatures = t.has("features.0");

    // Customers list handling
    // next-intl doesn't easily iterate over objects in a generic way without raw, 
    // but we can use a known count or just assume the structure.
    // For simplicity, we'll try to get the raw array if available or just hardcode the count if needed.
    // However, the best way in next-intl for lists is often to use the range approach.
    const customerIndices = Array.from({ length: 24 }, (_, i) => i);

    return (
        <div className="min-h-screen bg-[#f8fafc]">
            <PageHero
                title={t("title")}
                subtitle={t("subtitle")}
                bgGradient={bgGradient}
            />

            {/* Main Content Section */}
            {/* Main Content Section - Now only Title and Features at top */}
            <div className="container mx-auto px-4 pt-24">
                <motion.div
                    initial={{ opacity: 0, y: -20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    viewport={{ once: true }}
                    className="max-w-4xl"
                >
                    <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-6 leading-tight">
                        {t("title")}
                    </h2>
                    <p className="text-lg text-slate-600 leading-relaxed mb-8 italic border-l-4 border-blue-600 pl-6">
                        "{t("desc")}"
                    </p>

                    {hasFeatures && (
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mt-8">
                            {featureIndices.map((i) => {
                                if (!t.has(`features.${i}`)) return null;
                                return (
                                    <div key={i} className="flex gap-3 items-start p-4 bg-white rounded-2xl shadow-sm border border-slate-100">
                                        <div className="mt-1">
                                            <CheckCircle2 className="w-5 h-5 text-blue-600" />
                                        </div>
                                        <p className="text-slate-700 font-medium">
                                            {t(`features.${i}`)}
                                        </p>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </motion.div>
            </div>

            {/* Representative Customers Section - Moved Up */}
            <div className="container mx-auto px-4 pt-32 pb-24">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    viewport={{ once: true }}
                >
                    <div className="text-center mb-16">
                        <h2 className="text-3xl md:text-4xl font-bold text-slate-900 mb-4">
                            {t("representative_title")}
                        </h2>
                        <div className="w-20 h-1.5 bg-blue-600 mx-auto rounded-full" />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {customerIndices.map((i) => {
                            if (!t.has(`customers.${i}.name`)) return null;
                            return (
                                <motion.div
                                    key={i}
                                    initial={{ opacity: 0, y: 10 }}
                                    whileInView={{ opacity: 1, y: 0 }}
                                    transition={{ duration: 0.4, delay: i * 0.05 }}
                                    viewport={{ once: true }}
                                    className="group p-6 bg-white rounded-2xl border border-slate-100 hover:border-blue-200 hover:shadow-xl hover:shadow-blue-900/5 transition-all duration-300"
                                >
                                    <div className="flex items-center gap-4 mb-3">
                                        <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">
                                            <Building2 className="w-5 h-5" />
                                        </div>
                                        <h3 className="font-bold text-slate-900 group-hover:text-blue-700 transition-colors">
                                            {t(`customers.${i}.name`)}
                                        </h3>
                                    </div>
                                    <div className="flex items-center gap-2 text-sm text-slate-500 pl-14">
                                        <Globe className="w-4 h-4 opacity-50" />
                                        <span>{t(`customers.${i}.industry`)}</span>
                                    </div>
                                </motion.div>
                            );
                        })}
                    </div>
                </motion.div>
            </div>

            {/* Bottom Section - Image and Contact Us moved here */}
            <div className="container mx-auto px-4 pb-32">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center bg-white p-8 lg:p-16 rounded-[3rem] shadow-xl shadow-slate-200/50 border border-slate-100">
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6 }}
                        viewport={{ once: true }}
                        className="relative"
                    >
                        <div className="aspect-[4/3] rounded-[2rem] overflow-hidden shadow-2xl">
                            <img
                                src={imageSrc}
                                alt={t("title")}
                                className="w-full h-full object-cover hover:scale-105 transition-transform duration-700"
                            />
                            <div className="absolute inset-0 bg-gradient-to-tr from-blue-900/40 to-transparent mix-blend-multiply" />
                        </div>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6 }}
                        viewport={{ once: true }}
                        className="space-y-8"
                    >
                        <h3 className="text-3xl font-bold text-slate-900">
                            {t("cta_title")}
                        </h3>
                        <p className="text-lg text-slate-600">
                            {t("cta_desc")}
                        </p>
                        <div className="flex items-center gap-4 pt-4">
                            <Link
                                href="/contact"
                                className="px-10 py-5 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-700 transition-all hover:shadow-2xl hover:shadow-blue-600/30 inline-flex items-center gap-3 group"
                            >
                                {tNav("contact")} 
                                <ArrowRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                            </Link>
                        </div>
                    </motion.div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useTranslations } from "next-intl";
import PageHero from "@/components/PageHero";
import { Link } from "@/i18n/routing";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, ArrowRight, Calendar, Tag, ChevronLeft, ChevronRight } from "lucide-react";
import { useState, useEffect } from "react";
import { newsArticles } from "@/data/news";
import type { NewsArticle } from "@/data/news";

// Category badge color map
const categoryColors: Record<string, { bg: string; text: string; dot: string }> = {
    ai:       { bg: "bg-purple-50",  text: "text-purple-700",  dot: "bg-purple-500"  },
    security: { bg: "bg-red-50",     text: "text-red-700",     dot: "bg-red-500"     },
    cloud:    { bg: "bg-blue-50",    text: "text-blue-700",    dot: "bg-blue-500"    },
    company:  { bg: "bg-green-50",   text: "text-green-700",   dot: "bg-green-500"   },
    industry: { bg: "bg-amber-50",   text: "text-amber-700",   dot: "bg-amber-500"   },
};

const fallbackImage = "/images/unsplash/photo-1551434678-e076c223a692.jpg";

export default function NewsView({ locale }: { locale: string }) {
    const t = useTranslations("News_Page");
    const tNav = useTranslations("Navigation");
    const [currentPage, setCurrentPage] = useState(1);
    const lang = locale as "en" | "zh";

    const ITEMS_PER_PAGE = 6;
    const totalPages = Math.ceil(newsArticles.length / ITEMS_PER_PAGE);

    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    const paginatedArticles = newsArticles.slice(startIndex, startIndex + ITEMS_PER_PAGE);

    // Scroll to top when page changes
    useEffect(() => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }, [currentPage]);

    return (
        <div className="min-h-screen bg-[#f8fafc]">
            <PageHero title={t("title")} subtitle={t("subtitle")} />

            <div className="container mx-auto px-4 py-20">
                {/* News Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    <AnimatePresence mode="wait">
                        {paginatedArticles.map((article, index) => {
                        const colors = categoryColors[article.category] ?? {
                            bg: "bg-slate-50", text: "text-slate-700", dot: "bg-slate-400",
                        };
                        const imgSrc = article.image || fallbackImage;
                        const title   = article.title[lang]   ?? article.title.en;
                        const excerpt = article.excerpt[lang]  ?? article.excerpt.en;
                        const date    = article.date[lang]     ?? article.date.en;

                        return (
                            <motion.article
                                key={article.id}
                                initial={{ opacity: 0, y: 24 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ duration: 0.4, delay: index * 0.07 }}
                                className="group bg-white rounded-2xl overflow-hidden border border-slate-200 hover:border-blue-300 hover:shadow-xl hover:shadow-blue-500/5 transition-all duration-300 flex flex-col"
                            >
                                {/* Card Image */}
                                <div className="relative h-48 overflow-hidden bg-slate-100">
                                    <img
                                        src={imgSrc}
                                        alt={title}
                                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                                        onError={(e) => {
                                            (e.target as HTMLImageElement).src = fallbackImage;
                                        }}
                                    />
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/30 to-transparent" />

                                    {/* Category badge */}
                                    <div className={`absolute top-3 left-3 flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold ${colors.bg} ${colors.text}`}>
                                        <span className={`w-1.5 h-1.5 rounded-full ${colors.dot}`} />
                                        {t(`categories.${article.category}`)}
                                    </div>
                                </div>

                                {/* Card Body */}
                                <div className="flex flex-col flex-1 p-6">
                                    <div className="flex items-center gap-1.5 text-xs text-slate-400 mb-3">
                                        <Calendar className="w-3.5 h-3.5" />
                                        {date}
                                    </div>
                                    <h2 className="text-lg font-bold text-slate-900 mb-3 leading-snug group-hover:text-blue-600 transition-colors line-clamp-3">
                                        {title}
                                    </h2>
                                    <p className="text-sm text-slate-500 leading-relaxed flex-1 line-clamp-3">
                                        {excerpt}
                                    </p>

                                    {/* Read More ΓÇö real link to article page */}
                                    <div className="mt-6 pt-4 border-t border-slate-100">
                                        <Link
                                            href={`/news/${article.id}`}
                                            className="inline-flex items-center gap-1.5 text-sm font-semibold text-blue-600 group-hover:gap-3 transition-all"
                                        >
                                            {t("read_more")}
                                            <ArrowRight className="w-4 h-4" />
                                        </Link>
                                    </div>
                                </div>
                            </motion.article>
                        );
                    })}
                    </AnimatePresence>
                </div>

                {/* Pagination Controls */}
                {totalPages > 1 && (
                    <div className="flex justify-center items-center gap-2 mt-16">
                        <button
                            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                            disabled={currentPage === 1}
                            className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 disabled:opacity-30 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors"
                        >
                            <ChevronLeft className="w-5 h-5" />
                        </button>

                        <div className="flex gap-2">
                            {Array.from({ length: totalPages }, (_, i) => i + 1).map((pageNum) => (
                                <button
                                    key={pageNum}
                                    onClick={() => setCurrentPage(pageNum)}
                                    className={`w-10 h-10 rounded-lg border text-sm font-semibold transition-all ${
                                        currentPage === pageNum
                                            ? "bg-blue-600 text-white border-blue-600 shadow-md shadow-blue-200"
                                            : "bg-white text-slate-600 border-slate-200 hover:border-blue-400 hover:text-blue-600"
                                    }`}
                                >
                                    {pageNum}
                                </button>
                            ))}
                        </div>

                        <button
                            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                            disabled={currentPage === totalPages}
                            className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 disabled:opacity-30 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors"
                        >
                            <ChevronRight className="w-5 h-5" />
                        </button>
                    </div>
                )}

                {newsArticles.length === 0 && (
                    <div className="text-center py-24 text-slate-400">
                        <Tag className="w-12 h-12 mx-auto mb-4 opacity-30" />
                        <p className="text-lg">{t("no_articles")}</p>
                    </div>
                )}

                {/* CTA Banner */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.6 }}
                    className="mt-20 rounded-3xl bg-gradient-to-br from-blue-600 to-blue-800 p-10 md:p-16 text-white text-center"
                >
                    <h3 className="text-2xl md:text-3xl font-bold mb-4">
                        {t("cta_title")}
                    </h3>
                    <p className="text-blue-100 mb-8 max-w-xl mx-auto">
                        {t("cta_subtitle")}
                    </p>
                    <Link
                        href="/contact"
                        className="inline-flex items-center gap-2 px-8 py-4 bg-white text-blue-700 font-bold rounded-xl hover:bg-blue-50 transition-colors shadow-lg"
                    >
                        {tNav("contact")} <ArrowRight className="w-5 h-5" />
                    </Link>
                </motion.div>
            </div>
        </div>
    );
}

"use client";

import { useTranslations } from "next-intl";
import { Link } from "@/i18n/routing";
import { motion } from "framer-motion";
import { ArrowLeft, Calendar, Tag, Play } from "lucide-react";
import type { NewsArticle } from "@/data/news";

const categoryColors: Record<string, { bg: string; text: string; dot: string }> = {
    ai:       { bg: "bg-purple-100", text: "text-purple-700", dot: "bg-purple-500" },
    security: { bg: "bg-red-100",    text: "text-red-700",    dot: "bg-red-500"    },
    cloud:    { bg: "bg-blue-100",   text: "text-blue-700",   dot: "bg-blue-500"   },
    company:  { bg: "bg-green-100",  text: "text-green-700",  dot: "bg-green-500"  },
    industry: { bg: "bg-amber-100",  text: "text-amber-700",  dot: "bg-amber-500"  },
};

export default function ArticleView({
    article,
    locale,
}: {
    article: NewsArticle;
    locale: string;
}) {
    const t = useTranslations("News_Page");
    const tNav = useTranslations("Navigation");
    const lang = locale as "en" | "zh";
    const colors = categoryColors[article.category] ?? {
        bg: "bg-slate-100", text: "text-slate-700", dot: "bg-slate-400"
    };

    // Split body into paragraphs on double newline
    const paragraphs = (article.body[lang] ?? article.body.en)
        .split("\n\n")
        .map((p) => p.trim())
        .filter(Boolean);

    return (
        <div className="min-h-screen bg-[#f8fafc]">
            {/* Hero image */}
            <div className="relative h-72 md:h-96 w-full overflow-hidden bg-slate-900">
                <img
                    src={article.image}
                    alt={article.title[lang]}
                    className="w-full h-full object-cover opacity-60"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-slate-900/80 via-slate-900/30 to-transparent" />

                {/* Back link */}
                <div className="absolute top-24 left-0 right-0 container mx-auto px-4">
                    <Link
                        href="/news"
                        className="inline-flex items-center gap-2 text-sm text-white/80 hover:text-white transition-colors"
                    >
                        <ArrowLeft className="w-4 h-4" />
                        {tNav("news")}
                    </Link>
                </div>

                {/* Title block */}
                <div className="absolute bottom-0 left-0 right-0 container mx-auto px-4 pb-10">
                    <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold mb-4 ${colors.bg} ${colors.text}`}>
                        <span className={`w-1.5 h-1.5 rounded-full ${colors.dot}`} />
                        {t(`categories.${article.category}`)}
                    </div>
                    <h1 className="text-2xl md:text-4xl font-bold text-white leading-tight max-w-3xl">
                        {article.title[lang] ?? article.title.en}
                    </h1>
                    <div className="flex items-center gap-2 mt-4 text-sm text-white/60">
                        <Calendar className="w-4 h-4" />
                        {article.date[lang] ?? article.date.en}
                    </div>
                </div>
            </div>

            {/* Article body */}
            <div className="container mx-auto px-4 py-16">
                <div className="max-w-3xl mx-auto">
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.5 }}
                        className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 md:p-12"
                    >
                        {/* Excerpt lead */}
                        <p className="text-lg md:text-xl text-slate-600 font-medium leading-relaxed border-l-4 border-blue-500 pl-6 mb-10">
                            {article.excerpt[lang] ?? article.excerpt.en}
                        </p>

                        {/* Body paragraphs */}
                        <div className="prose prose-slate max-w-none space-y-5">
                            {paragraphs.map((para, idx) => {
                                // Detect bullet lines starting with ΓÇó
                                if (para.startsWith("ΓÇó")) {
                                    const bullets = para.split("\n").filter(Boolean);
                                    return (
                                        <ul key={idx} className="list-none space-y-2 pl-2">
                                            {bullets.map((b, bi) => (
                                                <li key={bi} className="flex items-start gap-3 text-slate-700">
                                                    <span className="mt-1.5 w-1.5 h-1.5 rounded-full bg-blue-500 shrink-0" />
                                                    <span>{b.replace(/^ΓÇó\s*/, "")}</span>
                                                </li>
                                            ))}
                                        </ul>
                                    );
                                }
                                return (
                                    <p key={idx} className="text-slate-700 leading-relaxed">
                                        {para}
                                    </p>
                                );
                            })}
                        </div>

                        {/* Video Link */}
                        {article.videoUrl && (
                            <div className="mt-12 pt-10 border-t border-slate-100">
                                <a
                                    href={article.videoUrl}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="group flex items-center justify-between p-6 rounded-2xl bg-slate-50 border border-slate-200 hover:border-blue-500/50 hover:bg-blue-50/30 transition-all shadow-sm"
                                >
                                    <div className="flex items-center gap-4">
